"use strict";dotclear.ready(()=>{const e=dotclear.getData("typo");for(const t of e.items){const e=document.querySelectorAll(`form[action^="${t.url}"]`);for(const r of e)if(""===t.id||r.getAttribute("id")===t.id)for(const e of t.selectors){const t=r.querySelectorAll(e);for(const e of t)!e||e.readOnly||e.disabled||(e.addEventListener("blur",()=>{const t=e.value;""!==t&&dotclear.jsonServicesGet("typoTransform",r=>{r.ret&&t!==r.buffer&&(e.value=r.buffer)},{buffer:t})}),e.addEventListener("keypress",t=>{"Enter"===t?.key&&e.blur()}))}}});
